// META_ANALYSIS_v1 (v0.3) - extraction des effets (LLM) + pooling inverse-variance
// fixe + aleatoire (DerSimonian-Laird), heterogeneite Q/I2/tau2, intervalle de prediction,
// test d'Egger, forest plot + funnel plot (SVG). Mesures: OR/RR/HR (log) et MD/SMD (lineaire).
const PROXY = 'http://host.docker.internal:3456';
const items = $input.all();
const articles = items.map(i => i.json);
const a0 = articles[0] || {};
const OUTCOME = (a0._meta_outcome || a0.question || '').toString();
let MEASURE = (a0._meta_measure || 'auto').toString().toUpperCase();
const LOGM = { OR:1, RR:1, HR:1 };
console.log('[Meta] ' + articles.length + ' articles, mesure=' + MEASURE);

function extractJson(raw){ if(!raw) return null; let s=String(raw).replace(/```json/gi,'').replace(/```/g,''); const i=s.indexOf('{'),j=s.lastIndexOf('}'); if(i<0||j<=i) return null; const f=s.substring(i,j+1); try{return JSON.parse(f);}catch(e){} try{return JSON.parse(f.replace(/,\s*([}\]])/g,'$1'));}catch(e){} return null; }
function num(x){ const v=parseFloat(x); return isFinite(v)?v:null; }

// PONT EXTRACTION -> META (interactivite 0.4.3) : reutilise des donnees chiffrees deja
// disponibles (module Extraction preset "meta-ready", cle=schema meta ; OU _meta_data
// precalcule/verifie par l'humain) plutot que de relancer un appel LLM. Rend null si rien
// d'exploitable -> extraction LLM classique (retro-compatible).
function reuseExisting(art){
  var md = art._meta_data;
  if (md && typeof md==='object' && md.data_type && md.data_type!=='none') return md;
  var ex = art._extracted; if (!ex || typeof ex!=='object') return null;
  var ei=num(ex.events_intervention), ni=num(ex.n_intervention), ec=num(ex.events_control), nc=num(ex.n_control);
  var mi=num(ex.mean_intervention), si=num(ex.sd_intervention), mc=num(ex.mean_control), sc=num(ex.sd_control);
  var eff=num(ex.effect), lo=num(ex.ci_lower), hi=num(ex.ci_upper);
  var base = { outcome: ((ex.outcome!=null?ex.outcome:(art._meta_outcome||''))+''), design: ((ex.design||'')+'').toLowerCase()||undefined, _reused:true };
  if (ei!=null && ni!=null && ec!=null && nc!=null)
    return Object.assign(base, { data_type:'binary', events_intervention:ei, n_intervention:ni, events_control:ec, n_control:nc });
  if (mi!=null && si!=null && ni!=null && mc!=null && sc!=null && nc!=null)
    return Object.assign(base, { data_type:'continuous', mean_intervention:mi, sd_intervention:si, n_intervention:ni, mean_control:mc, sd_control:sc, n_control:nc });
  if (eff!=null && lo!=null && hi!=null)
    return Object.assign(base, { data_type:'precomputed', effect_measure:((ex.effect_measure||'')+'').toUpperCase()||undefined, effect:eff, ci_lower:lo, ci_upper:hi });
  return null;
}

function buildPrompt(a, text){
  return [
    'Extract the quantitative result for the MAIN outcome of this study, for a meta-analysis.',
    OUTCOME ? ('TARGET OUTCOME (focus on this if present): ' + OUTCOME.substring(0,200)) : '',
    '',
    'TITLE: ' + ((a.title||'').substring(0,200)),
    'TEXT: ' + (text||'').toString().substring(0,8000),
    '',
    'Return STRICT JSON ONLY:',
    '{',
    '  "outcome": "<short outcome name>",',
    '  "design": "rct" | "nonrandomized",',
    '  "data_type": "binary" | "continuous" | "precomputed" | "none",',
    '  "events_intervention": <int|null>, "n_intervention": <int|null>,',
    '  "events_control": <int|null>, "n_control": <int|null>,',
    '  "mean_intervention": <num|null>, "sd_intervention": <num|null>,',
    '  "mean_control": <num|null>, "sd_control": <num|null>,',
    '  "effect_measure": "OR"|"RR"|"HR"|"MD"|"SMD"|null, "effect": <num|null>, "ci_lower": <num|null>, "ci_upper": <num|null>',
    '}',
    'Use "none" if no usable quantitative result is reported. Numbers only (no text, no %).'
  ].filter(Boolean).join('\n');
}

// derive yi (effect, log space si ratio) + vi pour la mesure demandee
function deriveEffect(d, measure){
  const isLog = !!LOGM[measure];
  // binary -> OR / RR (donnees brutes prioritaires si presentes)
  if ((measure==='OR'||measure==='RR')){
    let a=num(d.events_intervention), n1=num(d.n_intervention), c=num(d.events_control), n2=num(d.n_control);
    if (a!=null&&n1!=null&&c!=null&&n2!=null&&n1>0&&n2>0){
      let b=n1-a, dd=n2-c;
      if (a<=0||b<=0||c<=0||dd<=0){ a+=0.5;b+=0.5;c+=0.5;dd+=0.5; }
      if (measure==='OR'){ const yi=Math.log((a*dd)/(b*c)); const vi=1/a+1/b+1/c+1/dd; return {yi:yi,vi:vi}; }
      const r1=a/(a+b), r2=c/(c+dd); const yi=Math.log(r1/r2); const vi=1/a-1/(a+b)+1/c-1/(c+dd); return {yi:yi,vi:vi};
    }
  }
  // continuous -> MD / SMD (donnees brutes)
  if ((measure==='MD'||measure==='SMD')){
    const m1=num(d.mean_intervention), s1=num(d.sd_intervention), n1=num(d.n_intervention);
    const m2=num(d.mean_control), s2=num(d.sd_control), n2=num(d.n_control);
    if (![m1,s1,n1,m2,s2,n2].some(function(x){return x==null;}) && n1>0 && n2>0 && s1>=0 && s2>=0){
      if (measure==='MD'){ const yi=m1-m2; const vi=(s1*s1)/n1+(s2*s2)/n2; return {yi:yi,vi:vi}; }
      const sp=Math.sqrt(((n1-1)*s1*s1+(n2-1)*s2*s2)/(n1+n2-2));
      if (sp>0){ const dd=(m1-m2)/sp; const J=1-3/(4*(n1+n2)-9); const g=J*dd; const vi=(n1+n2)/(n1*n2)+g*g/(2*(n1+n2)); return {yi:g,vi:vi}; }
    }
  }
  // effet + IC pre-calcules (fallback, quel que soit data_type)
  if (d.effect!=null && d.ci_lower!=null && d.ci_upper!=null){
    const em=(d.effect_measure||measure||'').toUpperCase();
    const pl=!!LOGM[em];
    if (em && em!==measure) return null; // mesure incompatible
    let eff=num(d.effect), lo=num(d.ci_lower), hi=num(d.ci_upper);
    if (eff==null||lo==null||hi==null||hi<=lo) return null;
    if (pl){ if(eff<=0||lo<=0||hi<=0) return null; const yi=Math.log(eff), se=(Math.log(hi)-Math.log(lo))/(2*1.96); return {yi:yi,vi:se*se}; }
    const yi=eff, se=(hi-lo)/(2*1.96); return {yi:yi,vi:se*se};
  }
  return null;
}

// ---- 1. Extraction LLM par article ----
const studies = [];
for (let i=0;i<articles.length;i++){
  const art = articles[i];
  // STUDY_GROUPS_v1 (F3 v2) : companion papers - un seul rapport par ETUDE entre dans le pool
  // (unite d'analyse Cochrane = l'etude). Le regroupement est pose par /api/study-groups
  // (bouton Appliquer du chargeur de corpus) : les rapports non-primaires sont ecartes ici.
  if (art._study_group && art._study_group_primary === false){
    art._meta_status = 'companion_skipped';
    art._meta_included = false;
    art._meta_note = 'rapport secondaire du groupe ' + art._study_group + ' - seul le rapport principal est poole';
    continue;
  }
  // PONT : donnees deja extraites/verifiees -> on saute l'appel LLM (economie + tracabilite)
  const __reused = reuseExisting(art);
  if (__reused){ art._meta_data = __reused; art._meta_status='extracted'; art._meta_basis='reused'; studies.push(art); continue; }
  // Texte : PDF integral si dispo (les chiffres sont souvent dans les tableaux/resultats), sinon abstract
  let basis='abstract', text='';
  const pdf = art.pdf_local || '';
  if (pdf){ try { const resp=await this.helpers.httpRequest({ method:'POST', url:PROXY+'/extract-pdf', body:JSON.stringify({ pdf_path:pdf, max_chars:24000, skip_biblio:true }), headers:{'Content-Type':'application/json'}, json:true, timeout:60000 }); if(resp&&resp.success&&resp.text){ text=resp.text.substring(0,22000); basis='fulltext'; } } catch(e){} }
  if (!text){ text=(art.abstract||'').toString(); basis='abstract'; }
  if (!text || text.length<40){ art._meta_status='no_text'; continue; }
  art._meta_basis=basis;
  const prompt = buildPrompt(art, text);
  let parsed=null, raw='';
  try { const rp=await this.helpers.httpRequest({ method:'POST', url:PROXY+'/api/generate', body:JSON.stringify({ model:'qwen2.5:3b', prompt:prompt, stream:false, format:'json', options:{temperature:0,num_predict:600,num_ctx:32768}, keep_alive:'30m', _ultralab_task:'extraction' }), headers:{'Content-Type':'application/json'}, json:true, timeout:900000 }); raw=(rp&&rp.response)||''; parsed=extractJson(raw); } catch(e){}
  if (!parsed || parsed.data_type==='none' || !parsed.data_type){ art._meta_status='no_data'; art._meta_raw=raw.substring(0,150); continue; }
  art._meta_data=parsed; art._meta_status='extracted';
  studies.push(art);
}

// mesure auto = inferee du 1er study exploitable
if (MEASURE==='AUTO'){
  const first = studies.find(function(s){ const t=s._meta_data.data_type; return t==='binary'||t==='continuous'||t==='precomputed'; });
  if (first){ const t=first._meta_data.data_type; const em=(first._meta_data.effect_measure||'').toUpperCase(); MEASURE = (t==='binary')?'OR':(t==='continuous')?'SMD':(em||'OR'); }
  else MEASURE='OR';
}
const isLog = !!LOGM[MEASURE];

// ---- 2. Derivation des effets ----
const eff = [];
for (const s of studies){
  const e = deriveEffect(s._meta_data, MEASURE);
  if (e && isFinite(e.yi) && isFinite(e.vi) && e.vi>0){
    s._meta_yi=e.yi; s._meta_vi=e.vi; s._meta_se=Math.sqrt(e.vi); s._meta_included=true;
    eff.push(s);
  } else { s._meta_included=false; s._meta_status='incompatible'; }
}

const summary = { outcome: OUTCOME, measure: MEASURE, is_log: isLog, k: eff.length, n_excluded: studies.length-eff.length, total: articles.length };

if (eff.length >= 2){
  // ---- 3. Pooling ----
  let sumW=0,sumWy=0,sumW2=0;
  for (const s of eff){ const w=1/s._meta_vi; sumW+=w; sumWy+=w*s._meta_yi; sumW2+=w*w; }
  const ybarF=sumWy/sumW;
  let Q=0; for (const s of eff){ Q+=(1/s._meta_vi)*Math.pow(s._meta_yi-ybarF,2); }
  const df=eff.length-1;
  const C=sumW-sumW2/sumW;
  const tau2=(C>0)?Math.max(0,(Q-df)/C):0;
  const I2=(Q>df && Q>0)?Math.max(0,(Q-df)/Q)*100:0;
  let sumWs=0,sumWsy=0; for (const s of eff){ const ws=1/(s._meta_vi+tau2); sumWs+=ws; sumWsy+=ws*s._meta_yi; s._meta_wstar=ws; }
  const ybarR=sumWsy/sumWs; const varR=1/sumWs; const seR=Math.sqrt(varR);
  for (const s of eff){ s._meta_weight=Math.round(s._meta_wstar/sumWs*1000)/10; }
  const ciRl=ybarR-1.96*seR, ciRh=ybarR+1.96*seR;
  const varF=1/sumW, seF=Math.sqrt(varF);
  const piL=ybarR-1.96*Math.sqrt(tau2+varR), piH=ybarR+1.96*Math.sqrt(tau2+varR);
  // Egger (k>=3)
  let egger=null;
  if (eff.length>=3){
    const xs=eff.map(function(s){return 1/s._meta_se;}); const ys=eff.map(function(s){return s._meta_yi/s._meta_se;});
    const n=xs.length; const mx=xs.reduce(function(a,b){return a+b;},0)/n, my=ys.reduce(function(a,b){return a+b;},0)/n;
    let sxx=0,sxy=0; for(let i=0;i<n;i++){ sxx+=(xs[i]-mx)*(xs[i]-mx); sxy+=(xs[i]-mx)*(ys[i]-my); }
    const slope=sxy/sxx; const intercept=my-slope*mx;
    let sse=0; for(let i=0;i<n;i++){ const pred=intercept+slope*xs[i]; sse+=(ys[i]-pred)*(ys[i]-pred); }
    const s2=sse/(n-2); const seInt=Math.sqrt(s2*(1/n+mx*mx/sxx)); const t=seInt>0?intercept/seInt:0;
    egger={ intercept:Math.round(intercept*1000)/1000, t:Math.round(t*100)/100, df:n-2, note:'asymetrie funnel (exploratoire)' };
  }
  function bt(x){ return isLog?Math.exp(x):x; }
  function r3(x){ return Math.round(x*1000)/1000; }
  summary.fixed = { effect:r3(bt(ybarF)), ci_low:r3(bt(ybarF-1.96*seF)), ci_high:r3(bt(ybarF+1.96*seF)) };
  summary.random = { effect:r3(bt(ybarR)), ci_low:r3(bt(ciRl)), ci_high:r3(bt(ciRh)) };
  summary.prediction_interval = { low:r3(bt(piL)), high:r3(bt(piH)) };
  summary.heterogeneity = { Q:r3(Q), df:df, I2:Math.round(I2*10)/10, tau2:r3(tau2) };
  summary.egger = egger;
  summary.null_value = isLog?1:0;
  // back-transform per-study pour affichage
  for (const s of eff){ s._meta_effect=r3(bt(s._meta_yi)); s._meta_ci_low=r3(bt(s._meta_yi-1.96*s._meta_se)); s._meta_ci_high=r3(bt(s._meta_yi+1.96*s._meta_se)); }
  summary.pooled_yi=ybarR; summary.pooled_seR=seR;

  // ---- 4. SVG forest + funnel ----
  summary.forest_svg = buildForest(eff, summary);
  summary.funnel_svg = buildFunnel(eff, ybarR, seR, isLog);
} else {
  summary.error = 'Pas assez d etudes exploitables (k='+eff.length+', minimum 2). Donnees d effet absentes ou heterogenes.';
}

function esc(s){ return String(s==null?'':s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;'); }
function buildForest(arr, sm){
  const isLog=sm.is_log; const W=760, rowH=22, top=46, left=300, plotW=300, right=left+plotW;
  const H=top+arr.length*rowH+70;
  // bornes axe (unites d'affichage)
  let lo=Infinity,hi=-Infinity; arr.forEach(function(s){ lo=Math.min(lo,s._meta_ci_low); hi=Math.max(hi,s._meta_ci_high); });
  lo=Math.min(lo,sm.random.ci_low); hi=Math.max(hi,sm.random.ci_high);
  function tx(v){ if(isLog){ const a=Math.log(Math.max(lo,1e-6)),b=Math.log(hi),x=Math.log(Math.max(v,1e-6)); return left+(x-a)/(b-a)*plotW; } return left+(v-lo)/(hi-lo)*plotW; }
  const nx=tx(sm.null_value);
  const o=[];
  o.push('<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 '+W+' '+H+'" font-family="Segoe UI,Arial,sans-serif" font-size="12">');
  o.push('<rect width="'+W+'" height="'+H+'" fill="#ffffff"/>');
  o.push('<text x="12" y="20" font-size="14" font-weight="700" fill="#1a237e">Forest plot &#8212; '+esc(sm.measure)+(sm.outcome?(' : '+esc(sm.outcome.substring(0,60))):'')+'</text>');
  o.push('<text x="12" y="'+(top-14)+'" font-weight="600">Etude</text><text x="'+(right+10)+'" y="'+(top-14)+'" font-weight="600">'+esc(sm.measure)+' [IC 95%]</text>');
  o.push('<line x1="'+nx+'" y1="'+top+'" x2="'+nx+'" y2="'+(top+arr.length*rowH+6)+'" stroke="#999" stroke-dasharray="3,3"/>');
  arr.forEach(function(s,i){ const y=top+i*rowH+rowH/2; const x1=tx(s._meta_ci_low),x2=tx(s._meta_ci_high),xc=tx(s._meta_effect); const sz=4+Math.sqrt((s._meta_weight||1))*1.5;
    o.push('<text x="12" y="'+(y+4)+'">'+esc((s.title||'?').substring(0,40))+'</text>');
    o.push('<line x1="'+x1+'" y1="'+y+'" x2="'+x2+'" y2="'+y+'" stroke="#333"/>');
    o.push('<rect x="'+(xc-sz/2)+'" y="'+(y-sz/2)+'" width="'+sz+'" height="'+sz+'" fill="#3949ab"/>');
    o.push('<text x="'+(right+10)+'" y="'+(y+4)+'">'+s._meta_effect+' ['+s._meta_ci_low+', '+s._meta_ci_high+'] '+(s._meta_weight!=null?('('+s._meta_weight+'%)'):'')+'</text>');
  });
  // diamant pooled
  const yd=top+arr.length*rowH+18; const dl=tx(sm.random.ci_low),dr=tx(sm.random.ci_high),dc=tx(sm.random.effect);
  o.push('<polygon points="'+dl+','+yd+' '+dc+','+(yd-7)+' '+dr+','+yd+' '+dc+','+(yd+7)+'" fill="#c62828"/>');
  o.push('<text x="12" y="'+(yd+4)+'" font-weight="700">Global (aleatoire)</text>');
  o.push('<text x="'+(right+10)+'" y="'+(yd+4)+'" font-weight="700">'+sm.random.effect+' ['+sm.random.ci_low+', '+sm.random.ci_high+']</text>');
  o.push('<text x="12" y="'+(yd+24)+'" fill="#555">I&#178; = '+sm.heterogeneity.I2+'% &#183; &#964;&#178; = '+sm.heterogeneity.tau2+' &#183; Q = '+sm.heterogeneity.Q+' (df '+sm.heterogeneity.df+')</text>');
  o.push('</svg>');
  return o.join('');
}
function buildFunnel(arr, pooledYi, seR, isLog){
  const W=520,H=420,top=40,left=60,plotW=420,plotH=320;
  let semax=0,xlo=Infinity,xhi=-Infinity; arr.forEach(function(s){ semax=Math.max(semax,s._meta_se); xlo=Math.min(xlo,s._meta_yi-1.96*semax); xhi=Math.max(xhi,s._meta_yi+1.96*semax); });
  xlo=Math.min(xlo,pooledYi-1.96*semax); xhi=Math.max(xhi,pooledYi+1.96*semax); if(xhi<=xlo){xhi=xlo+1;}
  function tx(v){ return left+(v-xlo)/(xhi-xlo)*plotW; }
  function ty(se){ return top+(se/(semax||1))*plotH; } // SE 0 en haut
  const o=[];
  o.push('<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 '+W+' '+H+'" font-family="Segoe UI,Arial,sans-serif" font-size="11">');
  o.push('<rect width="'+W+'" height="'+H+'" fill="#ffffff"/>');
  o.push('<text x="12" y="20" font-size="13" font-weight="700" fill="#1a237e">Funnel plot</text>');
  // funnel 95% : x = pooled +/- 1.96*se
  const apexX=tx(pooledYi), apexY=ty(0); const blX=tx(pooledYi-1.96*semax), blY=ty(semax), brX=tx(pooledYi+1.96*semax);
  o.push('<polygon points="'+apexX+','+apexY+' '+blX+','+blY+' '+brX+','+blY+'" fill="#eceff1" stroke="#b0bec5"/>');
  o.push('<line x1="'+apexX+'" y1="'+apexY+'" x2="'+apexX+'" y2="'+blY+'" stroke="#90a4ae" stroke-dasharray="3,3"/>');
  // axes
  o.push('<line x1="'+left+'" y1="'+top+'" x2="'+left+'" y2="'+(top+plotH)+'" stroke="#333"/>');
  o.push('<text x="14" y="'+(top+plotH/2)+'" transform="rotate(-90 14,'+(top+plotH/2)+')">Erreur standard</text>');
  o.push('<text x="'+(left+plotW/2-30)+'" y="'+(top+plotH+30)+'">Effet ('+(isLog?'log':'')+')</text>');
  arr.forEach(function(s){ o.push('<circle cx="'+tx(s._meta_yi)+'" cy="'+ty(s._meta_se)+'" r="4" fill="#3949ab" fill-opacity="0.7"/>'); });
  o.push('</svg>');
  return o.join('');
}

a0._meta_summary = summary;
console.log('[Meta] k='+summary.k+' measure='+summary.measure+(summary.random?(' pooled='+summary.random.effect+' I2='+summary.heterogeneity.I2+'%'):' (insuffisant)'));
return articles.map(function(x){ return { json:x }; });
